17	  const policyItemsByStep: Record<number, Item[]> = {};
18	  const previousPaidByStep: Record<number, number> = {};
19	
20	  scenario.steps.forEach((step, index) => {
21	    if (step.op === "quote") {
22	      const premium = quote(scenario.customer, step.items);
23	      policyItemsByStep[index] = step.items;
24	      previousPaidByStep[index] = 0;
25	      results.push({ premium });
